 83→type CommentThreadProps = {
 84→  comment: JournalComment;
 85→  postId: string;
 86→  allComments: JournalComment[];
 87→  isLoggedIn: boolean;
 88→  onReply: (commentId: string, userName: string) => void;
 89→  onToggleReplies: (commentId: string) => void;
 90→  expandedReplies: Set<string>;
 91→  colors: Palette;
 92→  depth: number;
 93→};
 94→
 95→function CommentThread({
 96→  comment,
 97→  postId,
 98→  allComments,
 99→  isLoggedIn,
100→  onReply,
101→  onToggleReplies,
102→  expandedReplies,
103→  colors,
104→  depth,
105→}: CommentThreadProps) {
106→  const isExpanded = expandedReplies.has(comment.id);
107→  const replies = allComments.filter(c => c.parent_id === comment.id);
108→  const replyCount = comment.reply_count ?? replies.length;
109→  const userName = comment.users?.name || 'User';
110→
111→  const avatarSize = depth === 0 ? 28 : 24;
112→  const bodyPaddingLeft = depth === 0 ? 36 : 32;
113→  const repliesMarginLeft = depth === 0 ? 36 : 24;
114→
115→  return (
116→    <View>
117→      <View style={[styles.commentCard, {borderTopColor: colors.borderCard}]}>
118→        <View style={styles.commentHeader}>
119→          <Avatar
120→            uri={(comment.users as any)?.image_url}
121→            name={comment.users?.name}
122→            size={avatarSize}
123→          />
124→          <View style={styles.commentMeta}>
125→            <Text style={[styles.commentAuthor, {color: colors.textPrimary}]}>
126→              {userName}
127→            </Text>
128→            <Text style={[styles.commentTime, {color: colors.textFaint}]}>
129→              {formatRelativeDate(comment.created_at)}
130→            </Text>
131→          </View>
132→        </View>
133→        <Text style={[styles.commentBody, {color: colors.textSecondary, paddingLeft: bodyPaddingLeft}]}>
134→          {comment.comment || ''}
135→        </Text>
136→        <View style={[styles.commentActions, {paddingLeft: bodyPaddingLeft}]}>
137→          {isLoggedIn && (
138→            <Pressable
139→              style={styles.actionButton}
140→              onPress={() => onReply(comment.id, userName)}>
141→              <ReplyIcon size={14} color={colors.textMuted} />
142→              <Text style={[styles.actionText, {color: colors.textMuted}]}>
143→                Reply
144→              </Text>
145→            </Pressable>
146→          )}
147→          {replyCount > 0 && (
148→            <Pressable
149→              style={styles.actionButton}
150→              onPress={() => onToggleReplies(comment.id)}>
151→              <Text style={[styles.actionText, {color: colors.accentGold}]}>
152→                {isExpanded ? 'Hide replies' : `Show ${replyCount} ${replyCount === 1 ? 'reply' : 'replies'}`}
153→              </Text>
154→            </Pressable>
155→          )}
156→        </View>
157→      </View>
158→
159→      {isExpanded && (
160→        <View style={[styles.repliesContainer, {borderLeftColor: colors.borderLight, marginLeft: repliesMarginLeft}]}>
161→          {replies.map(reply => (
162→            <CommentThread
163→              key={reply.id}
164→              comment={reply}
165→              postId={postId}
166→              allComments={allComments}
167→              isLoggedIn={isLoggedIn}
168→              onReply={onReply}
169→              onToggleReplies={onToggleReplies}
170→              expandedReplies={expandedReplies}
171→              colors={colors}
172→              depth={depth + 1}
173→            />
174→          ))}
175→        </View>
176→      )}
177→    </View>
178→  );
179→}
